프로젝트 구조와 컨벤션을 충분히 파악했습니다. 이제 프로필 수정 API 인터페이스를 설계하겠습니다.

---

# 프로필 수정 API 인터페이스 설계

## 1. 현재 프로젝트 구조 분석 결과

코드베이스 탐색 결과, 실제 애플리케이션 소스 파일은 없는 초기 상태입니다. 다음 컨벤션을 프로젝트 스킬 파일 기준으로 도출했습니다.

- 파일 위치: `graphql/src/main/resources/graphql/profile.graphqls`
- Proto 위치: `protobuf/src/main/proto/profile/profile.proto`
- Controller 위치: `graphql/src/main/kotlin/com/maum/backend/controller/profile/`
- Service 위치: `graphql/src/main/kotlin/com/maum/backend/service/profile/`
- DB Catalog: `maum` (user, profile 도메인)

---

## 2. GraphQL 스키마

파일 경로: `graphql/src/main/resources/graphql/profile.graphqls`

```graphql
# ───────────────────────────────────────────
# Enum 타입
# ───────────────────────────────────────────

enum Gender {
    MALE
    FEMALE
    NON_BINARY
    PREFER_NOT_TO_SAY
}

enum ProfilePhotoAction {
    ADD
    DELETE
    REORDER
}

# ───────────────────────────────────────────
# 반환 타입
# ───────────────────────────────────────────

"""소셜/데이팅 앱 사용자 프로필"""
type Profile {
    userId: ID!
    nickname: String!
    bio: String
    birthYear: Int!
    age: Int!                          # 서버 계산 (birthYear 기반)
    gender: Gender!
    height: Int                        # cm 단위, nullable
    job: String
    location: String                   # 시/구 단위 문자열 (ex: "서울 마포구")
    interests: [String!]!              # 관심사 태그 목록
    languages: [String!]!             # 사용 언어 (ex: ["ko", "en"])
    photos: [ProfilePhoto!]!
    voiceIntroUrl: String             # 음성 소개 URL (Maum 앱 특화)
    isProfileComplete: Boolean!       # 필수 필드 모두 입력 여부
    updatedAt: String!
}

type ProfilePhoto {
    photoId: ID!
    url: String!
    order: Int!                        # 대표 사진 = order 0
    isMain: Boolean!
}

type UpdateProfileResult {
    profile: Profile!
    updatedFields: [String!]!         # 실제 변경된 필드 목록
}

# ───────────────────────────────────────────
# Input 타입
# ───────────────────────────────────────────

input UpdateProfileInput {
    nickname: String                   # 1~20자, 특수문자 제한
    bio: String                        # 최대 200자, null 허용
    birthYear: Int                     # 1900~현재년도, 변경 시 나이 재계산
    gender: Gender
    height: Int                        # 140~220 cm
    job: String                        # 최대 30자
    location: String                   # 최대 50자
    interests: [String!]              # 최대 10개, 각 항목 최대 15자
    languages: [String!]              # BCP-47 언어 코드 목록
    voiceIntroUrl: String             # S3 presigned URL로 업로드 후 URL 전달
    photoUpdates: [ProfilePhotoUpdateInput!]
}

input ProfilePhotoUpdateInput {
    action: ProfilePhotoAction!
    photoId: String                   # DELETE / REORDER 시 필수
    uploadedUrl: String               # ADD 시 필수 (S3 업로드 후 URL)
    order: Int                        # REORDER 시 필수 (0 = 대표 사진)
}

# ───────────────────────────────────────────
# Query / Mutation
# ───────────────────────────────────────────

extend type Query {
    """내 프로필 조회"""
    myProfile: Profile!

    """다른 사용자 프로필 조회 (소셜/매칭 용도)"""
    userProfile(userId: ID!): Profile
}

extend type Mutation {
    """프로필 수정 (부분 업데이트 - 전달된 필드만 수정)"""
    updateProfile(input: UpdateProfileInput!): UpdateProfileResult!

    """프로필 사진 순서 일괄 변경"""
    reorderProfilePhotos(photoIds: [ID!]!): [ProfilePhoto!]!

    """음성 소개 삭제"""
    deleteVoiceIntro: Boolean!
}
```

