## 3. gRPC Proto 정의

파일 경로: `protobuf/src/main/proto/profile/profile.proto`

```protobuf
syntax = "proto3";
package profile;

option java_multiple_files = true;
option java_package = "com.maum.backend.protobuf.profile";

// ───────────────────────────────────────────
// Service
// ───────────────────────────────────────────

service ProfileService {
  rpc GetProfile(GetProfileRequest) returns (GetProfileResponse);
  rpc UpdateProfile(UpdateProfileRequest) returns (UpdateProfileResponse);
  rpc UpdateProfilePhotos(UpdateProfilePhotosRequest) returns (UpdateProfilePhotosResponse);
  rpc DeleteVoiceIntro(DeleteVoiceIntroRequest) returns (DeleteVoiceIntroResponse);
}

// ───────────────────────────────────────────
// Enum
// ───────────────────────────────────────────

enum Gender {
  GENDER_UNSPECIFIED = 0;
  MALE = 1;
  FEMALE = 2;
  NON_BINARY = 3;
  PREFER_NOT_TO_SAY = 4;
}

enum PhotoAction {
  PHOTO_ACTION_UNSPECIFIED = 0;
  ADD = 1;
  DELETE = 2;
  REORDER = 3;
}

// ───────────────────────────────────────────
// 공통 메시지
// ───────────────────────────────────────────

message ProfileProto {
  string user_id = 1;
  string nickname = 2;
  optional string bio = 3;
  int32 birth_year = 4;
  int32 age = 5;
  Gender gender = 6;
  optional int32 height = 7;
  optional string job = 8;
  optional string location = 9;
  repeated string interests = 10;
  repeated string languages = 11;
  repeated ProfilePhotoProto photos = 12;
  optional string voice_intro_url = 13;
  bool is_profile_complete = 14;
  string updated_at = 15;
}

message ProfilePhotoProto {
  string photo_id = 1;
  string url = 2;
  int32 order = 3;
  bool is_main = 4;
}

// ───────────────────────────────────────────
// GetProfile
// ───────────────────────────────────────────

message GetProfileRequest {
  string requester_user_id = 1;   // 요청자 (권한 체크 용도)
  string target_user_id = 2;      // 조회 대상 (본인 조회 시 동일값)
}

message GetProfileResponse {
  ProfileProto profile = 1;
}

// ───────────────────────────────────────────
// UpdateProfile
// ───────────────────────────────────────────

message UpdateProfileRequest {
  string user_id = 1;
  optional string nickname = 2;
  optional string bio = 3;        // 빈 문자열("")은 bio 삭제로 처리
  optional int32 birth_year = 4;
  optional int32 gender = 5;      // Gender enum 정수값
  optional int32 height = 6;      // 0이면 height 필드 삭제로 처리
  optional string job = 7;
  optional string location = 8;
  repeated string interests = 10; // 전체 교체 방식
  repeated string languages = 11; // 전체 교체 방식
  optional string voice_intro_url = 12;
  bool has_interests_update = 13; // interests 빈 배열 교체와 미전달 구분용 플래그
  bool has_languages_update = 14;
}

message UpdateProfileResponse {
  ProfileProto profile = 1;
  repeated string updated_fields = 2;
}

// ───────────────────────────────────────────
// UpdateProfilePhotos
// ───────────────────────────────────────────

message PhotoUpdate {
  PhotoAction action = 1;
  optional string photo_id = 2;
  optional string uploaded_url = 3;
  optional int32 order = 4;
}

message UpdateProfilePhotosRequest {
  string user_id = 1;
  repeated PhotoUpdate photo_updates = 2;
}

message UpdateProfilePhotosResponse {
  repeated ProfilePhotoProto photos = 1;
}

// ───────────────────────────────────────────
// DeleteVoiceIntro
// ───────────────────────────────────────────

message DeleteVoiceIntroRequest {
  string user_id = 1;
}

message DeleteVoiceIntroResponse {
  bool success = 1;
}
```

