## 4. GraphQL Controller (Kotlin)

파일 경로: `graphql/src/main/kotlin/com/maum/backend/controller/profile/ProfileController.kt`

```kotlin
@Controller
class ProfileController(
    private val profileService: ProfileGrpcService,
) {
    @QueryMapping
    @PreAuthorize("hasAuthority('User')")
    fun myProfile(
        @UserId userId: String,
    ): ProfileResponse {
        val response = profileService.getProfile(userId, userId)
        return response.profile.toResponse()
    }

    @QueryMapping
    @PreAuthorize("hasAuthority('User')")
    fun userProfile(
        @UserId userId: String,
        @Argument userId: String,
    ): ProfileResponse? {
        val response = profileService.getProfile(userId, userId)
        return response.profile?.toResponse()
    }

    @MutationMapping
    @PreAuthorize("hasAuthority('User')")
    fun updateProfile(
        @UserId userId: String,
        @Argument input: UpdateProfileInput,
    ): UpdateProfileResultResponse {
        val response = profileService.updateProfile(userId, input)
        return UpdateProfileResultResponse(
            profile = response.profile.toResponse(),
            updatedFields = response.updatedFieldsList,
        )
    }

    @MutationMapping
    @PreAuthorize("hasAuthority('User')")
    fun reorderProfilePhotos(
        @UserId userId: String,
        @Argument photoIds: List<String>,
    ): List<ProfilePhotoResponse> {
        val response = profileService.reorderPhotos(userId, photoIds)
        return response.photosList.map { it.toResponse() }
    }

    @MutationMapping
    @PreAuthorize("hasAuthority('User')")
    fun deleteVoiceIntro(
        @UserId userId: String,
    ): Boolean {
        val response = profileService.deleteVoiceIntro(userId)
        return response.success
    }
}
```

